import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './Dashboard.css';

function Dashboard() {
  const [user, setUser] = useState(null);
  const [interviews, setInterviews] = useState([]);
  const [stats, setStats] = useState({
    totalInterviews: 0,
    averageScore: 0,
    bestScore: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/dashboard', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        setInterviews(data.interviews);
        setStats(data.stats);
      } else {
        setError(data.message || 'Failed to load dashboard');
      }
    } catch (err) {
      console.error('Dashboard error:', err);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="dashboard-page">
      <div className="container">
        <div className="dashboard-header fade-in">
          <div>
            <h1>Welcome back, {user?.name}! 👋</h1>
            <p>Track your progress and continue improving your interview skills</p>
          </div>
          <div className="dashboard-actions">
            <Link to="/interview" className="btn btn-primary">
              Start Interview
            </Link>
            <Link to="/practice" className="btn btn-secondary">
              Practice Mode
            </Link>
          </div>
        </div>

        <div className="dashboard-stats">
          <div className="stat-card slide-in">
            <div className="stat-icon">📊</div>
            <div className="stat-content">
              <h3>Total Interviews</h3>
              <p className="stat-value">{interviews.length}</p>
            </div>
          </div>
          <div className="stat-card slide-in" style={{animationDelay: '0.1s'}}>
            <div className="stat-icon">⭐</div>
            <div className="stat-content">
              <h3>Average Score</h3>
              <p className="stat-value">
                {interviews.length > 0 
                  ? Math.round(interviews.reduce((acc, i) => acc + i.score, 0) / interviews.length)
                  : 0}
              </p>
            </div>
          </div>
          <div className="stat-card slide-in" style={{animationDelay: '0.2s'}}>
            <div className="stat-icon">🎯</div>
            <div className="stat-content">
              <h3>Best Score</h3>
              <p className="stat-value">
                {interviews.length > 0 
                  ? Math.max(...interviews.map(i => i.score))
                  : 0}
              </p>
            </div>
          </div>
        </div>

        <div className="dashboard-content">
          <div className="section-header">
            <h2>Recent Interviews</h2>
          </div>

          {loading ? (
            <div className="spinner"></div>
          ) : interviews.length > 0 ? (
            <div className="interviews-list">
              {interviews.map((interview) => (
                <div key={interview.id} className="interview-card">
                  <div className="interview-info">
                    <h3>{interview.type}</h3>
                    <p className="interview-date">{new Date(interview.date).toLocaleDateString()}</p>
                  </div>
                  <div className="interview-score">
                    <div className="score-circle" style={{
                      background: `conic-gradient(var(--primary) ${interview.score * 3.6}deg, var(--border) 0deg)`
                    }}>
                      <div className="score-inner">
                        {interview.score}
                      </div>
                    </div>
                  </div>
                  <button className="btn btn-secondary btn-small">View Details</button>
                </div>
              ))}
            </div>
          ) : (
            <div className="empty-state">
              <div className="empty-icon">📝</div>
              <h3>No interviews yet</h3>
              <p>Start your first interview to see your progress here</p>
              <Link to="/interview" className="btn btn-primary">
                Start Interview
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
